function normalizeJoinedDate(value) {
  if (value == null) return null;
  if (typeof value !== "string") return value;
  const v = value.trim();
  if (!v) return null;

  const yearOnly = v.match(/^(\d{4})$/);
  if (yearOnly) return yearOnly[1];

  const yearMonth = v.match(/^(\d{4})-(\d{1,2})$/);
  if (yearMonth) {
    const yyyy = yearMonth[1];
    const mm = yearMonth[2].padStart(2, "0");
    return `${yyyy}-${mm}`;
  }

  const yearMonthDay = v.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
  if (yearMonthDay) {
    const yyyy = yearMonthDay[1];
    const mm = yearMonthDay[2].padStart(2, "0");
    const dd = yearMonthDay[3].padStart(2, "0");
    return `${yyyy}-${mm}-${dd}`;
  }

  const exactDmy = v.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (exactDmy) {
    const dd = exactDmy[1].padStart(2, "0");
    const mm = exactDmy[2].padStart(2, "0");
    const yyyy = exactDmy[3];
    return `${yyyy}-${mm}-${dd}`;
  }

  return null;
}

function getJoinedDateRange(value) {
  const v = normalizeJoinedDate(value);
  if (!v) return null;
  if (/^\d{4}$/.test(v)) {
    return [`${v}-01-01`, `${v}-12-31`];
  }
  if (/^\d{4}-\d{2}$/.test(v)) {
    const [yyyy, mm] = v.split("-");
    const month = parseInt(mm, 10);
    const lastDay = new Date(parseInt(yyyy, 10), month, 0).getDate();
    return [`${yyyy}-${mm}-01`, `${yyyy}-${mm}-${String(lastDay).padStart(2, "0")}`];
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) {
    return [v, v];
  }
  return null;
}

function formatJoinedForDisplay(value) {
  const v = normalizeJoinedDate(value);
  if (!v) return "";
  if (/^\d{4}$/.test(v)) return v;
  if (/^\d{4}-\d{2}$/.test(v)) {
    const [yyyy, mm] = v.split("-");
    const date = new Date(parseInt(yyyy, 10), parseInt(mm, 10) - 1, 1);
    return date.toLocaleDateString(undefined, { year: "numeric", month: "long" });
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) {
    const [yyyy, mm, dd] = v.split("-");
    const date = new Date(parseInt(yyyy, 10), parseInt(mm, 10) - 1, parseInt(dd, 10));
    if (Number.isNaN(date.getTime())) return v;
    return date.toLocaleDateString(undefined, { year: "numeric", month: "long", day: "numeric" });
  }
  return v;
}

// ─── PERSISTENT STORAGE HOOK ──────────────────────────────────────────────────
function usePersisted(key, initial, ownerId = null) {
  const storageKey = "tlob_" + key;
  const userModifiedRef = useRef(false);
  const [val, setVal] = useState(() => {
    if (!isSupabaseConfigured || !supabase || !ownerId) {
      try {
        const stored = localStorage.getItem(storageKey);
        return stored ? JSON.parse(stored) : initial;
      } catch {
        return initial;
      }
    }
    return initial;
  });
  const [hydrated, setHydrated] = useState(false);
  const saveTimerRef = useRef(null);

  const setValWithUserAction = useCallback((next) => {
    userModifiedRef.current = true;
    setVal(next);
  }, [setVal]);

  useEffect(() => {
    let cancelled = false;
    setHydrated(false);

    async function hydrate() {
      // Default: localStorage
      const hydrateFromLocalStorage = () => {
        try {
          const stored = localStorage.getItem(storageKey);
          return stored ? JSON.parse(stored) : initial;
        } catch {
          return initial;
        }
      };

      if (!isSupabaseConfigured || !supabase || !ownerId) {
        const next = hydrateFromLocalStorage();
        if (!cancelled && !userModifiedRef.current) {
          setVal(next);
        }
        if (!cancelled) {
          setHydrated(true);
        }
        return;
      }

      try {
        const { data, error } = await supabase
          .from("app_kv")
          .select("value")
          .eq("owner_id", ownerId)
          .eq("key", storageKey)
          .maybeSingle();

        if (error) throw error;

        const next = data?.value ?? initial;
        if (!cancelled && !userModifiedRef.current) {
          setVal(next);
        }
        if (!cancelled) {
          setHydrated(true);
        }
      } catch {
        // If Supabase is misconfigured/offline, fall back gracefully.
        const next = hydrateFromLocalStorage();
        if (!cancelled && !userModifiedRef.current) {
          setVal(next);
        }
        if (!cancelled) {
          setHydrated(true);
        }
      }
    }

    hydrate();
    return () => {
      cancelled = true;
    };
  }, [storageKey, initial, ownerId]);

  useEffect(() => {
    if (!hydrated) return;

    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(async () => {
      if (!isSupabaseConfigured || !supabase || !ownerId) {
        try {
          localStorage.setItem(storageKey, JSON.stringify(val));
        } catch {}
        return;
      }

      try {
        await supabase.from("app_kv").upsert(
          { owner_id: ownerId, key: storageKey, value: val },
          { onConflict: "owner_id,key" }
        );
      } catch {
        // If the DB write fails, keep the app functional and persist locally.
        try {
          localStorage.setItem(storageKey, JSON.stringify(val));
        } catch {}
      }
    }, 450);

    return () => {
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    };
  }, [hydrated, ownerId, storageKey, val]);

  return [val, setValWithUserAction];
}

// ─── TABLE-BACKED STORAGE HOOK (Supabase) ─────────────────────────────────────
function useSupabaseTable(tableName, initialArray, ownerId) {
  const [rows, setRows] = useState(initialArray);
  const [hydrated, setHydrated] = useState(false);
  const saveTimerRef = useRef(null);
  const lastSyncedIdsRef = useRef(new Set());
  const lastSyncedFingerprintRef = useRef(new Map()); // id -> JSON fingerprint of DB row
  const userChangedRef = useRef(false);
  const latestRowsRef = useRef(rows);
  const [syncStatus, setSyncStatus] = useState({ state: "idle", lastSavedAt: null, error: null });
  const syncNowRef = useRef(async () => {});

  const normalizeDate = useCallback((value) => {
    if (value == null) return null;
    if (typeof value !== "string") return value;
    const v = value.trim();
    if (!v) return null;
    // Already ISO yyyy-mm-dd
    if (/^\d{4}-\d{2}-\d{2}$/.test(v)) return v;
    // Convert dd/mm/yyyy -> yyyy-mm-dd
    const m = v.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if (m) {
      const dd = m[1].padStart(2, "0");
      const mm = m[2].padStart(2, "0");
      const yyyy = m[3];
      return `${yyyy}-${mm}-${dd}`;
    }
    // Unknown format: let it be null instead of breaking inserts
    return null;
  }, []);

  const toDbRow = useCallback((r) => {
    if (!r || typeof r !== "object") return r;

    // Supabase `date` columns cannot accept empty string; convert "" -> null.
    if (tableName === "members") {
      const out = { ...r };
      out.joined = normalizeJoinedDate(out.joined);
      out.birthday = normalizeDate(out.birthday);
      out.anniversary = normalizeDate(out.anniversary);
      // Map camelCase -> snake_case for DB compatibility
      if (out.ageGroup !== undefined) { out.age_group = out.ageGroup; delete out.ageGroup; }
      if (out.sourceEventId !== undefined) { out.source_event_id = out.sourceEventId; delete out.sourceEventId; }
      // Avoid storing base64 data URLs in Postgres (too large / slow). Use Supabase Storage later.
      if (typeof out.photo === "string" && out.photo.startsWith("data:")) out.photo = null;
      return out;
    }
    if (tableName === "events") {
      const out = { ...r };
      out.date = normalizeDate(out.date);
      return out;
    }
    if (tableName === "attendance") {
      const out = { ...r };
      // map camelCase -> snake_case
      if (out.memberId !== undefined) { out.member_id = out.memberId; delete out.memberId; }
      if (out.eventId !== undefined) { out.event_id = out.eventId; delete out.eventId; }
      if (out.memberName !== undefined) { out.member_name = out.memberName; delete out.memberName; }
      return out;
    }
    if (tableName === "visitors") {
      const out = { ...r };
      out.date = normalizeDate(out.date);
      // map camelCase -> snake_case
      if (out.eventId !== undefined) { out.event_id = out.eventId; delete out.eventId; }
      if (out.invitedBy !== undefined) { out.invited_by = out.invitedBy; delete out.invitedBy; }
      if (out.convertedToMember !== undefined) { out.converted_to_member = out.convertedToMember; delete out.convertedToMember; }
      return out;
    }
    return r;
  }, [tableName, normalizeDate]);

  const fromDbRow = useCallback((r) => {
    if (!r || typeof r !== "object") return r;
    if (tableName === "members") {
      const out = { ...r };
      if (out.age_group !== undefined) { out.ageGroup = out.age_group; delete out.age_group; }
      if (out.source_event_id !== undefined) { out.sourceEventId = out.source_event_id; delete out.source_event_id; }
      return out;
    }
    if (tableName === "attendance") {
      const out = { ...r };
      if (out.member_id !== undefined) { out.memberId = out.member_id; delete out.member_id; }
      if (out.event_id !== undefined) { out.eventId = out.event_id; delete out.event_id; }
      if (out.member_name !== undefined) { out.memberName = out.member_name; delete out.member_name; }
      return out;
    }
    if (tableName === "visitors") {
      const out = { ...r };
      if (out.event_id !== undefined) { out.eventId = out.event_id; delete out.event_id; }
      if (out.invited_by !== undefined) { out.invitedBy = out.invited_by; delete out.invited_by; }
      if (out.converted_to_member !== undefined) { out.convertedToMember = out.converted_to_member; delete out.converted_to_member; }
      return out;
    }
    return r;
  }, [tableName]);

  const setRowsUser = useCallback((updater) => {
    userChangedRef.current = true;
    setSyncStatus((s) => (s.state === "saving" ? s : { ...s, state: "saving", error: null }));

    const prev = latestRowsRef.current;
    const next = typeof updater === "function" ? updater(prev) : updater;
    latestRowsRef.current = next;
    setRows(next);

    // Best-effort immediate flush (so edits feel "directly saved")
    // Debounced effect still exists as a fallback.
    setTimeout(() => {
      syncNowRef.current().catch((e) => {
        // eslint-disable-next-line no-console
        console.error(`[Supabase save failed] table=${tableName}`, e);
        setSyncStatus((s) => ({ ...s, state: "error", error: e?.message || "Save failed" }));
      });
    }, 0);
  }, [tableName]);

  useEffect(() => {
    latestRowsRef.current = rows;
  }, [rows]);

  useEffect(() => {
    let cancelled = false;
    setHydrated(false);
    userChangedRef.current = false;
    setSyncStatus({ state: "idle", lastSavedAt: null, error: null });

    async function hydrate() {
      if (!isSupabaseConfigured || !supabase || !ownerId) {
        if (!cancelled) {
          setRows(initialArray);
          lastSyncedIdsRef.current = new Set((initialArray || []).map((r) => r?.id).filter(Boolean));
          setHydrated(true);
        }
        return;
      }

      try {
        const { data, error } = await supabase
          .from(tableName)
          .select("*")
          .eq("owner_id", ownerId);
        if (error) throw error;

        const cleaned = (data || []).map(({ owner_id, created_at, updated_at, ...rest }) => fromDbRow(rest));
        const next = cleaned.length ? cleaned : initialArray;
        if (!cancelled) {
          setRows(next);
          lastSyncedIdsRef.current = new Set((next || []).map((r) => r?.id).filter(Boolean));
          // build fingerprint map from server state
          const fp = new Map();
          (next || []).forEach((row) => {
            if (!row?.id) return;
            fp.set(row.id, JSON.stringify(toDbRow(row)));
          });
          lastSyncedFingerprintRef.current = fp;
          setHydrated(true);
        }
      } catch {
        if (!cancelled) {
          setRows(initialArray);
          lastSyncedIdsRef.current = new Set((initialArray || []).map((r) => r?.id).filter(Boolean));
          const fp = new Map();
          (initialArray || []).forEach((row) => {
            if (!row?.id) return;
            fp.set(row.id, JSON.stringify(toDbRow(row)));
          });
          lastSyncedFingerprintRef.current = fp;
          setHydrated(true);
        }
      }
    }

    hydrate();
    return () => {
      cancelled = true;
    };
  }, [tableName, ownerId, initialArray, fromDbRow, toDbRow]);

  const syncNow = useCallback(async () => {
    if (!hydrated) return;
    if (!isSupabaseConfigured || !supabase || !ownerId) return;
    if (!userChangedRef.current) return;

    setSyncStatus((s) => ({ ...s, state: "saving", error: null }));

    const current = latestRowsRef.current || [];
    const currentIds = new Set(current.map((r) => r?.id).filter(Boolean));
    const lastIds = lastSyncedIdsRef.current || new Set();
    const toDelete = [];
    lastIds.forEach((id) => {
      if (!currentIds.has(id)) toDelete.push(id);
    });

    if (toDelete.length) {
      const { error: delErr } = await supabase
        .from(tableName)
        .delete()
        .eq("owner_id", ownerId)
        .in("id", toDelete);
      if (delErr) throw delErr;
    }

    const lastFp = lastSyncedFingerprintRef.current || new Map();
    const changed = [];
    for (const row of current) {
      if (!row?.id) continue;
      const dbRow = toDbRow(row);
      const fp = JSON.stringify(dbRow);
      if (lastFp.get(row.id) !== fp) {
        changed.push({ owner_id: ownerId, ...dbRow });
      }
    }

    if (changed.length) {
      const { error: upErr } = await supabase
        .from(tableName)
        .upsert(changed, { onConflict: "owner_id,id" });

      // If the DB schema is missing a newly added column (common during incremental migrations),
      // retry without that column so the app remains usable.
      if (upErr) {
        const msg = String(upErr?.message || "");
        const code = String(upErr?.code || "");

        // PostgREST: schema cache missing column
        if (code === "PGRST204" && tableName === "members" && (msg.includes("age_group") || msg.includes("source_event_id"))) {
          const stripped = changed.map(({ age_group, source_event_id, ...rest }) => rest);
          const { error: retryErr } = await supabase
            .from(tableName)
            .upsert(stripped, { onConflict: "owner_id,id" });
          if (retryErr) throw retryErr;
        } else {
          throw upErr;
        }
      }
    }

    lastSyncedIdsRef.current = currentIds;
    // update fingerprints for current rows
    const nextFp = new Map(lastFp);
    current.forEach((row) => {
      if (!row?.id) return;
      nextFp.set(row.id, JSON.stringify(toDbRow(row)));
    });
    // remove deleted fingerprints
    toDelete.forEach((id) => nextFp.delete(id));
    lastSyncedFingerprintRef.current = nextFp;
    userChangedRef.current = false;
    setSyncStatus({ state: "saved", lastSavedAt: Date.now(), error: null });
  }, [hydrated, ownerId, tableName, toDbRow]);

  useEffect(() => {
    syncNowRef.current = syncNow;
  }, [syncNow]);

  useEffect(() => {
    if (!hydrated) return;
    if (!isSupabaseConfigured || !supabase || !ownerId) return;
    if (!userChangedRef.current) return;

    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(async () => {
      try {
        await syncNow();
      } catch (e) {
        // Surface errors for debugging; failing silently makes data look like it "doesn't save".
        // eslint-disable-next-line no-console
        console.error(`[Supabase save failed] table=${tableName}`, e);
        setSyncStatus((s) => ({ ...s, state: "error", error: e?.message || "Save failed" }));
      }
    }, 200);

    return () => {
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    };
  }, [hydrated, rows, tableName, ownerId, syncNow]);

  useEffect(() => {
    if (!hydrated) return;
    if (!isSupabaseConfigured || !supabase || !ownerId) return;

    // Flush pending writes on refresh/navigation to avoid "disappears then appears later".
    const onPageHide = () => {
      if (saveTimerRef.current) {
        clearTimeout(saveTimerRef.current);
        saveTimerRef.current = null;
      }
      // Fire-and-forget best effort.
      syncNow().catch(() => {});
    };

    window.addEventListener("pagehide", onPageHide);
    document.addEventListener("visibilitychange", () => {
      if (document.visibilityState === "hidden") onPageHide();
    });

    return () => {
      window.removeEventListener("pagehide", onPageHide);
    };
  }, [hydrated, ownerId, syncNow]);

  useEffect(() => {
    if (!hydrated) return;
    if (!isSupabaseConfigured || !supabase || !ownerId) return;

    // Realtime updates (instant UI refresh when DB changes).
    const channel = supabase
      .channel(`rt:${tableName}:${ownerId}`)
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: tableName,
          filter: `owner_id=eq.${ownerId}`,
        },
        async () => {
          try {
            const { data, error } = await supabase
              .from(tableName)
              .select("*")
              .eq("owner_id", ownerId);
            if (error) throw error;
            const cleaned = (data || []).map(({ owner_id, created_at, updated_at, ...rest }) => fromDbRow(rest));
            // Don't mark as a user change; this is server-authoritative.
            userChangedRef.current = false;
            lastSyncedIdsRef.current = new Set((cleaned || []).map((r) => r?.id).filter(Boolean));
            setRows(cleaned);
          } catch {
            // ignore
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [hydrated, ownerId, tableName, fromDbRow]);

  return [rows, setRowsUser, syncStatus];
}

